SELECT /* base.ec.pm :: PmPlan :: selectList */ * , ste.site_nm AS site_nm , cd_pt.code_label AS plan_type_cd_nm , cd_ps.code_label AS plan_status_cd_nm FROM pm_plan p LEFT JOIN sy_site ste ON ste.site_id = site_id LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PLAN_TYPE' AND cd_pt.code_value = plan_type_cd LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PLAN_STATUS' AND cd_ps.code_value = plan_status_cd
ORDER BY plan_id ASC ORDER BY plan_id DESC ORDER BY plan_nm ASC ORDER BY plan_nm DESC ORDER BY reg_date ASC ORDER BY reg_date DESC ORDER BY reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pm :: PmPlan :: selectPageList */ * , ste.site_nm AS site_nm , cd_pt.code_label AS plan_type_cd_nm , cd_ps.code_label AS plan_status_cd_nm FROM pm_plan p LEFT JOIN sy_site ste ON ste.site_id = site_id LEFT JOIN sy_code cd_pt ON cd_pt.code_grp = 'PLAN_TYPE' AND cd_pt.code_value = plan_type_cd LEFT JOIN sy_code cd_ps ON cd_ps.code_grp = 'PLAN_STATUS' AND cd_ps.code_value = plan_status_cd
ORDER BY plan_id ASC ORDER BY plan_id DESC ORDER BY plan_nm ASC ORDER BY plan_nm DESC ORDER BY reg_date ASC ORDER BY reg_date DESC ORDER BY reg_date DESC
LIMIT #{limit} OFFSET #{offset}

