UPDATE pm_plan /* base.ec.pm :: PmPlan :: updateSelective */
site_id = #{siteId}, plan_nm = #{planNm}, plan_title = #{planTitle}, plan_type_cd = #{planTypeCd}, plan_desc = #{planDesc}, thumbnail_url = #{thumbnailUrl}, banner_url = #{bannerUrl}, start_date = #{startDate}, end_date = #{endDate}, plan_status_cd = #{planStatusCd}, plan_status_cd_before = #{planStatusCdBefore}, sort_ord = #{sortOrd}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE plan_id = #{planId}
